import{_ as e,a,b as o}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as n,o as t,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Autenticazione e gestione dei dispositivi di accesso","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Safety/authentication-and-login-devices.md","filePath":"it-IT/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),r={name:"it-IT/Safety/authentication-and-login-devices.md"};function d(c,i,p,u,m,v){return t(),l("div",null,[...i[0]||(i[0]=[s('<h1 id="autenticazione-e-gestione-dei-dispositivi-di-accesso" tabindex="-1">Autenticazione e gestione dei dispositivi di accesso <a class="header-anchor" href="#autenticazione-e-gestione-dei-dispositivi-di-accesso" aria-label="Permalink to &quot;Autenticazione e gestione dei dispositivi di accesso&quot;">​</a></h1><p><code>Authentication Management</code> e <code>Login Device Management</code> proteggono il pannello admin di ImgBed, l&#39;area pubblica di upload e l&#39;accesso WebDAV.</p><p>Usa questa pagina per impostare le credenziali, controllare i dispositivi con sessione attiva e revocare vecchi accessi quando serve.</p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri il pannello admin e vai a:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>La pagina contiene due aree principali:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+e+'" alt="Gestione autenticazione" loading="lazy"></p><h2 id="a-cosa-serve-authentication-management" tabindex="-1">A cosa serve Authentication Management <a class="header-anchor" href="#a-cosa-serve-authentication-management" aria-label="Permalink to &quot;A cosa serve Authentication Management&quot;">​</a></h2><p>Authentication Management conserva le credenziali di accesso.</p><p>Ci sono due tipi di autenticazione:</p><ul><li>Autenticazione lato utente</li><li>Autenticazione lato admin</li></ul><h2 id="autenticazione-lato-utente" tabindex="-1">Autenticazione lato utente <a class="header-anchor" href="#autenticazione-lato-utente" aria-label="Permalink to &quot;Autenticazione lato utente&quot;">​</a></h2><p>L&#39;autenticazione lato utente è la password di upload.</p><p>Dopo aver impostato una password di upload, i visitatori devono inserirla prima di usare la pagina di caricamento. È utile quando non vuoi lasciare l&#39;upload pubblico aperto a chiunque.</p><p><img src="'+a+'" alt="Pagina login utente" loading="lazy"></p><h3 id="impostare-la-password-di-upload" tabindex="-1">Impostare la password di upload <a class="header-anchor" href="#impostare-la-password-di-upload" aria-label="Permalink to &quot;Impostare la password di upload&quot;">​</a></h3><p>Quando la password di upload è configurata:</p><ul><li>I visitatori devono inserirla prima di usare la pagina di upload.</li><li>Il caricamento è disponibile solo dopo password accettata.</li><li>Se le sessioni dispositivo lato utente sono abilitate, ImgBed registra quel dispositivo.</li></ul><p>Se cambi la password di upload, le vecchie sessioni lato utente vengono invalidate. I visitatori dovranno inserire la nuova password.</p><h2 id="autenticazione-lato-admin" tabindex="-1">Autenticazione lato admin <a class="header-anchor" href="#autenticazione-lato-admin" aria-label="Permalink to &quot;Autenticazione lato admin&quot;">​</a></h2><p>L&#39;autenticazione admin usa nome utente e password amministratore.</p><p>Protegge il pannello admin. In produzione è consigliato configurarla sempre.</p><p><img src="'+o+'" alt="Pagina login admin" loading="lazy"></p><h3 id="impostare-le-credenziali-admin" tabindex="-1">Impostare le credenziali admin <a class="header-anchor" href="#impostare-le-credenziali-admin" aria-label="Permalink to &quot;Impostare le credenziali admin&quot;">​</a></h3><p>Quando nome utente e password admin sono configurati:</p><ul><li>L&#39;apertura del pannello admin richiede il login.</li><li>Ogni login riuscito crea un record dispositivo admin.</li><li>Puoi rivedere, pulire o forzare offline i dispositivi in Login Device Management.</li></ul><p>Se cambi nome utente o password admin, le vecchie sessioni admin vengono invalidate. Dovrai accedere di nuovo.</p><h2 id="a-cosa-serve-login-device-management" tabindex="-1">A cosa serve Login Device Management <a class="header-anchor" href="#a-cosa-serve-login-device-management" aria-label="Permalink to &quot;A cosa serve Login Device Management&quot;">​</a></h2><p>Login Device Management mostra i dispositivi che hanno effettuato l&#39;accesso.</p><p>Ti aiuta a controllare:</p><ul><li>quali dispositivi hanno aperto il pannello admin.</li><li>quali dispositivi hanno usato la pagina upload lato utente.</li><li>quali client WebDAV si sono collegati.</li><li>se una sessione dispositivo è ancora valida.</li><li>se vecchi dispositivi devono essere forzati offline.</li></ul><p>La pagina ha tre schede:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="sicurezza-globale-dei-cookie" tabindex="-1">Sicurezza globale dei cookie <a class="header-anchor" href="#sicurezza-globale-dei-cookie" aria-label="Permalink to &quot;Sicurezza globale dei cookie&quot;">​</a></h2><p>In alto in Login Device Management puoi configurare il comportamento globale dei cookie.</p><h3 id="durata-cookie-utente" tabindex="-1">Durata cookie utente <a class="header-anchor" href="#durata-cookie-utente" aria-label="Permalink to &quot;Durata cookie utente&quot;">​</a></h3><p>Definisce per quanti giorni un login lato utente resta valido.</p><p>Per esempio, con 14 giorni, di solito i visitatori non devono reinserire la password di upload per due settimane.</p><h3 id="durata-cookie-admin" tabindex="-1">Durata cookie admin <a class="header-anchor" href="#durata-cookie-admin" aria-label="Permalink to &quot;Durata cookie admin&quot;">​</a></h3><p>Definisce per quanti giorni un login admin resta valido.</p><p>Per esempio, con 14 giorni, gli amministratori di solito non devono riaccedere per due settimane.</p><h3 id="modalita-sicura" tabindex="-1">Modalità sicura <a class="header-anchor" href="#modalita-sicura" aria-label="Permalink to &quot;Modalità sicura&quot;">​</a></h3><p>Con Secure mode attivo, il browser invia i cookie di login solo su HTTPS.</p><p>Attivalo sui siti HTTPS in produzione. Non attivarlo nei test locali HTTP, altrimenti potresti vedere il comportamento &quot;login riuscito, ma al refresh sono di nuovo disconnesso&quot;.</p><h2 id="dispositivi-login-admin" tabindex="-1">Dispositivi login admin <a class="header-anchor" href="#dispositivi-login-admin" aria-label="Permalink to &quot;Dispositivi login admin&quot;">​</a></h2><p>La scheda Admin mostra i dispositivi che hanno eseguito l&#39;accesso al pannello admin.</p><p>I record compaiono solo dopo aver configurato le credenziali admin e aver aperto il pannello tramite login.</p><p>Ogni scheda dispositivo può mostrare:</p><ul><li>informazioni su dispositivo e browser</li><li>IP del primo login</li><li>IP dell&#39;ultima attività</li><li>ora di login</li><li>ultima attività</li><li>scadenza</li><li>stato attuale</li></ul><p>Se vedi un dispositivo sconosciuto, usa <code>Force Offline</code> per invalidarlo.</p><h2 id="pulire-vecchi-dispositivi" tabindex="-1">Pulire vecchi dispositivi <a class="header-anchor" href="#pulire-vecchi-dispositivi" aria-label="Permalink to &quot;Pulire vecchi dispositivi&quot;">​</a></h2><p><code>Clean Up Old Devices</code> rimuove in blocco i vecchi record di login nella scheda corrente.</p><p>Usalo quando sospetti che vecchie sessioni siano ancora attive su altri dispositivi.</p><h2 id="forzare-offline" tabindex="-1">Forzare offline <a class="header-anchor" href="#forzare-offline" aria-label="Permalink to &quot;Forzare offline&quot;">​</a></h2><p><code>Force Offline</code> invalida una singola sessione dispositivo.</p><p>Dopo l&#39;operazione:</p><ul><li>i dispositivi admin devono accedere di nuovo.</li><li>i dispositivi lato utente devono reinserire la password di upload.</li><li>i client WebDAV devono autenticarsi di nuovo.</li></ul><p>Anche i dispositivi scaduti o non validi possono essere rimossi.</p><h2 id="uscire-dal-dispositivo-corrente" tabindex="-1">Uscire dal dispositivo corrente <a class="header-anchor" href="#uscire-dal-dispositivo-corrente" aria-label="Permalink to &quot;Uscire dal dispositivo corrente&quot;">​</a></h2><p>La scheda del dispositivo corrente è marcata come <code>Current Device</code>.</p><p>Dopo il logout del dispositivo corrente:</p><ul><li>la sessione admin corrente viene chiusa.</li><li>la sessione lato utente corrente viene chiusa.</li></ul><p>Devi accedere di nuovo prima di continuare a usare quell&#39;area.</p>',65)])])}const b=n(r,[["render",d]]);export{f as __pageData,b as default};
